    wl_fixes::wl_fixes(struct ::wl_client *client, uint32_t id, int version)
        : m_resource_map()
        , m_resource(nullptr)
        , m_global(nullptr)
    {
        init(client, id, version);
    }

    wl_fixes::wl_fixes(struct ::wl_display *display, int version)
        : m_resource_map()
        , m_resource(nullptr)
        , m_global(nullptr)
    {
        init(display, version);
    }

    wl_fixes::wl_fixes(struct ::wl_resource *resource)
        : m_resource_map()
        , m_resource(nullptr)
        , m_global(nullptr)
    {
        init(resource);
    }

    wl_fixes::wl_fixes()
        : m_resource_map()
        , m_resource(nullptr)
        , m_global(nullptr)
    {
    }

    wl_fixes::~wl_fixes()
    {
        for (auto resource : std::as_const(m_resource_map))
            resource->fixes_object = nullptr;

        if (m_resource)
            m_resource->fixes_object = nullptr;

        if (m_global) {
            wl_global_destroy(m_global);
            wl_list_remove(&m_displayDestroyedListener.link);
        }
    }

    void wl_fixes::init(struct ::wl_client *client, uint32_t id, int version)
    {
        m_resource = bind(client, id, version);
    }

    void wl_fixes::init(struct ::wl_resource *resource)
    {
        m_resource = bind(resource);
    }

    wl_fixes::Resource *wl_fixes::add(struct ::wl_client *client, int version)
    {
        Resource *resource = bind(client, 0, version);
        m_resource_map.insert(client, resource);
        return resource;
    }

    wl_fixes::Resource *wl_fixes::add(struct ::wl_client *client, uint32_t id, int version)
    {
        Resource *resource = bind(client, id, version);
        m_resource_map.insert(client, resource);
        return resource;
    }

    void wl_fixes::init(struct ::wl_display *display, int version)
    {
        m_global = wl_global_create(display, &::wl_fixes_interface, version, this, bind_func);
        m_displayDestroyedListener.notify = wl_fixes::display_destroy_func;
        m_displayDestroyedListener.parent = this;
        wl_display_add_destroy_listener(display, &m_displayDestroyedListener);
    }

    const struct wl_interface *wl_fixes::interface()
    {
        return &::wl_fixes_interface;
    }

    wl_fixes::Resource *wl_fixes::fixes_allocate()
    {
        return new Resource;
    }

    void wl_fixes::fixes_bind_resource(Resource *)
    {
    }

    void wl_fixes::fixes_destroy_resource(Resource *)
    {
    }

    void wl_fixes::bind_func(struct ::wl_client *client, void *data, uint32_t version, uint32_t id)
    {
        wl_fixes *that = static_cast<wl_fixes *>(data);
        that->add(client, id, version);
    }

    void wl_fixes::display_destroy_func(struct ::wl_listener *listener, void *data)
    {
        Q_UNUSED(data);
        wl_fixes *that = static_cast<wl_fixes::DisplayDestroyedListener *>(listener)->parent;
        that->m_global = nullptr;
    }

    void wl_fixes::destroy_func(struct ::wl_resource *client_resource)
    {
        Resource *resource = Resource::fromResource(client_resource);
        Q_ASSERT(resource);
        wl_fixes *that = resource->fixes_object;
        if (Q_LIKELY(that)) {
            that->m_resource_map.remove(resource->client(), resource);
            that->fixes_destroy_resource(resource);

            that = resource->fixes_object;
            if (that && that->m_resource == resource)
                that->m_resource = nullptr;
        }
        delete resource;
    }

    wl_fixes::Resource *wl_fixes::bind(struct ::wl_client *client, uint32_t id, int version)
    {
        Q_ASSERT_X(!wl_client_get_object(client, id), "QWaylandObject bind", QStringLiteral("binding to object %1 more than once").arg(id).toLocal8Bit().constData());
        struct ::wl_resource *handle = wl_resource_create(client, &::wl_fixes_interface, version, id);
        return bind(handle);
    }

    wl_fixes::Resource *wl_fixes::bind(struct ::wl_resource *handle)
    {
        Resource *resource = fixes_allocate();
        resource->fixes_object = this;

        wl_resource_set_implementation(handle, &m_wl_fixes_interface, resource, destroy_func);
        resource->handle = handle;
        fixes_bind_resource(resource);
        return resource;
    }
    wl_fixes::Resource *wl_fixes::Resource::fromResource(struct ::wl_resource *resource)
    {
        if (Q_UNLIKELY(!resource))
            return nullptr;
        if (wl_resource_instance_of(resource, &::wl_fixes_interface, &m_wl_fixes_interface))
            return static_cast<Resource *>(wl_resource_get_user_data(resource));
        return nullptr;
    }

